  ('5827d207-9510-572e-b5b4-4830933a3915', 'de-a1-articles-uhr', 'vocabulary', 'die Uhr', 'die oor', 'noun', 'Die Uhr ist rund.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-uhr.mp3', null, 'bee7886f-1b1b-4fa4-810a-a75cd68589b4', 24, true, '{"hint":{"de":"Uhr ist eine wichtige Ausnahme ohne -e. Kurz merken: die Uhr.","en":"Uhr is an important exception without -e. Just remember: die Uhr."},"kind":"article_noun","noun":"Uhr","article":"die","english":"clock","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('c191b9a4-14ba-56cf-827f-a88f6687e7cf', 'de-a1-articles-tuer', 'vocabulary', 'die Tür', 'die tür', 'noun', 'Die Tür ist offen.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-tuer.mp3', null, '4959a992-5997-4ac7-86bd-00f11d732c6e', 25, true, '{"hint":{"de":"Tür und Uhr sind kurze Ausnahmen. Beide sind die: die Tür, die Uhr.","en":"Tür and Uhr are short exceptions. Both use die: die Tür, die Uhr."},"kind":"article_noun","noun":"Tür","article":"die","english":"door","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('5f84a843-af5c-532e-9f88-e0a8b9377abd', 'de-a1-articles-schule', 'vocabulary', 'die Schule', 'die SHU-le', 'noun', 'Die Schule ist groß.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-articles-expanded-20260705/de-a1-articles-schule.mp3', null, '6ff92597-a7b3-4077-9d62-e874856650f4', 26, true, '{"hint":{"de":"Schule endet auf -e. Sehr oft hilft das: die Schule.","en":"Schule ends in -e. That is a strong hint for die: die Schule."},"kind":"article_noun","noun":"Schule","article":"die","english":"school","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('abbfaf86-3156-5a5e-9cf6-bc8e079d18cf', 'de-a1-articles-kueche', 'vocabulary', 'die Küche', 'die KÜ-che', 'noun', 'Die Küche ist sauber.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-articles-expanded-20260705/de-a1-articles-kueche.mp3', null, '53b82b52-698c-4d85-9b65-f7c6b2293d84', 27, true, '{"hint":{"de":"Küche endet auf -e. Das passt oft zu die: die Küche.","en":"Küche ends in -e. That often fits die: die Küche."},"kind":"article_noun","noun":"Küche","article":"die","english":"kitchen","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('c5cf9f49-98c2-577e-8c2a-57747dfd5d8d', 'de-a1-articles-help-die-das', 'info', 'Wann oft die oder das?', null, null, null, null, 'de-a1-articles', 'beginner', '# Wann oft die oder das?
**die** ist oft bei Wörtern auf **-e**. **das** ist sicher bei **-chen** und bei vielen Wörtern, die du fest als Paar lernst.

| die | das |
| die Tasche, die Schule | das Mädchen, das Fenster |', null, null, null, 18, true, '{"kind":"article_help","content_md":{"de":"# Wann oft die oder das?\n**die** ist oft bei Wörtern auf **-e**. **das** ist sicher bei **-chen** und bei vielen Wörtern, die du fest als Paar lernst.\n\n| die | das |\n| die Tasche, die Schule | das Mädchen, das Fenster |","en":"# When is it often die or das?\n**die** is often used with words ending in **-e**. **das** is certain with **-chen** and common with nouns you learn as fixed pairs.\n\n| die | das |\n| die Tasche, die Schule | das Mädchen, das Fenster |"},"lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('5afd94e7-811e-51fb-ba1d-88af604ec625', 'de-a1-articles-flasche', 'vocabulary', 'die Flasche', 'die FLASH-e', 'noun', 'Die Flasche ist leer.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-articles-expanded-20260705/de-a1-articles-flasche.mp3', null, '1e1f7165-d28d-4bcc-a58c-0f2106a8c464', 28, true, '{"hint":{"de":"Flasche endet auf -e. Merke die -e-Hilfe: die Flasche.","en":"Flasche ends in -e. Use the -e hint: die Flasche."},"kind":"article_noun","noun":"Flasche","article":"die","english":"bottle","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('02d3b5b4-ad47-5dce-af52-d77b9548d169', 'de-a1-articles-strasse', 'vocabulary', 'die Straße', 'die SHTRA-se', 'noun', 'Die Straße ist lang.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-articles-expanded-20260705/de-a1-articles-strasse.mp3', null, '2eaf7837-2291-4fa0-a730-15c0de7080b2', 29, true, '{"hint":{"de":"Straße endet auf -e. Bei vielen -e-Wörtern passt die.","en":"Straße ends in -e. Many -e words use die."},"kind":"article_noun","noun":"Straße","article":"die","english":"street","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
