  ('f15db869-d4a4-5ed3-a533-58678224e82b', 'de-a1-articles-haus', 'vocabulary', 'das Haus', 'das hous', 'noun', 'Das Haus ist alt.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-haus.mp3', null, 'b6c82618-a967-4c0d-93dd-9c96acebf2bf', 31, true, '{"hint":{"de":"Viele kurze Sachwörter musst du fest mit Artikel lernen. Für Haus gilt: das Haus.","en":"Many short object words must be learned with the article. For Haus: das Haus."},"kind":"article_noun","noun":"Haus","article":"das","english":"house","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('90ab9861-eb6a-5b29-a229-441c9e6baa3c', 'de-a1-articles-auto', 'vocabulary', 'das Auto', 'das AU-to', 'noun', 'Das Auto ist neu.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-auto.mp3', null, 'f52ad133-bf32-4285-8020-92f0c5f43512', 32, true, '{"hint":{"de":"Internationale Sachwörter sind oft das. Das hilft hier: das Auto.","en":"International object words are often das. This helps here: das Auto."},"kind":"article_noun","noun":"Auto","article":"das","english":"car","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
