  ('3ca9109a-fed8-517d-9f25-9287b13d47cc', 'de-a1-articles-fenster', 'vocabulary', 'das Fenster', 'das FENS-ter', 'noun', 'Das Fenster ist offen.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-fenster.mp3', null, '43b8aec0-3f52-4a82-be2d-3b8925c5bca3', 34, true, '{"hint":{"de":"Viele -er-Wörter sind der, aber Fenster ist eine wichtige Ausnahme: das Fenster.","en":"Many -er words use der, but Fenster is a key exception: das Fenster."},"kind":"article_noun","noun":"Fenster","article":"das","english":"window","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
