  ('c42a60b5-6e29-5582-8fbc-83840ae24810', 'de-a1-articles-help-learn-pairs', 'info', 'Artikel immer mit dem Wort lernen', null, null, null, null, 'de-a1-articles', 'beginner', '# Artikel immer mit dem Wort lernen
insert into language_cards_card_translations (card_id, lang_code, translation, example_translation, hint) values
  ('02d3b5b4-ad47-5dce-af52-d77b9548d169', 'de', 'die Straße', 'Die Straße ist lang.', 'Straße endet auf -e. Bei vielen -e-Wörtern passt die.'),
  ('02d3b5b4-ad47-5dce-af52-d77b9548d169', 'en', 'the street', 'Die Straße ist lang.', 'Straße ends in -e. Many -e words use die.'),
  ('03ce955e-e01c-5b39-8b00-ba87e8524939', 'de', 'das Bett', 'Das Bett ist weich.', 'Bett hat keine gute Regel. Als festes Paar lernen: das Bett.'),
  ('03ce955e-e01c-5b39-8b00-ba87e8524939', 'en', 'the bed', 'Das Bett ist weich.', 'Bett has no good rule. Learn it as a fixed pair: das Bett.'),
  ('05530905-7ec6-5a35-a7b1-33da285392c7', 'de', 'die Katze', 'Die Katze schläft.', 'Viele Wörter auf -e sind die. Katze endet auf -e: die Katze.'),
  ('05530905-7ec6-5a35-a7b1-33da285392c7', 'en', 'the cat', 'Die Katze schläft.', 'Many words ending in -e use die. Katze ends in -e: die Katze.'),
  ('0d4c94b9-8008-5ea9-af7a-1851c356023f', 'de', 'das Handy', 'Das Handy ist neu.', 'Viele moderne Sachwörter sind das. Für A1: das Handy.'),
  ('0d4c94b9-8008-5ea9-af7a-1851c356023f', 'en', 'the phone', 'Das Handy ist neu.', 'Many modern object words use das. For A1: das Handy.'),
  ('0d86c457-9f36-57b1-a6fa-10463708d481', 'de', 'das Zimmer', 'Das Zimmer ist hell.', 'Zimmer endet auf -er, ist aber eine wichtige Ausnahme: das Zimmer.'),
  ('0d86c457-9f36-57b1-a6fa-10463708d481', 'en', 'the room', 'Das Zimmer ist hell.', 'Zimmer ends in -er, but it is a key exception: das Zimmer.'),
  ('17a7f6df-2123-5de1-a229-f0908861f9b8', 'de', 'das Mädchen', 'Das Mädchen lacht.', 'Endung -chen ist immer das. Deshalb: das Mädchen.'),
  ('17a7f6df-2123-5de1-a229-f0908861f9b8', 'en', 'the girl', 'Das Mädchen lacht.', 'The ending -chen always uses das. So: das Mädchen.'),
  ('31d12d13-9892-5dec-a29e-1a9cf88d72b0', 'de', 'die Lampe', 'Die Lampe ist hell.', 'Lampe endet auf -e. Viele -e-Wörter sind die.'),
  ('31d12d13-9892-5dec-a29e-1a9cf88d72b0', 'en', 'the lamp', 'Die Lampe ist hell.', 'Lampe ends in -e. Many -e words use die.'),
  ('38666742-66de-5585-91f3-08ec731cfb69', 'de', 'die Tasche', 'Die Tasche ist voll.', 'Tasche endet auf -e. Das ist oft die: die Tasche.'),
  ('38666742-66de-5585-91f3-08ec731cfb69', 'en', 'the bag', 'Die Tasche ist voll.', 'Tasche ends in -e. That often points to die: die Tasche.'),
  ('3ca9109a-fed8-517d-9f25-9287b13d47cc', 'de', 'das Fenster', 'Das Fenster ist offen.', 'Viele -er-Wörter sind der, aber Fenster ist eine wichtige Ausnahme: das Fenster.'),
  ('3ca9109a-fed8-517d-9f25-9287b13d47cc', 'en', 'the window', 'Das Fenster ist offen.', 'Many -er words use der, but Fenster is a key exception: das Fenster.'),
  ('44959747-7f8f-53e5-81ac-08233e8edd21', 'de', 'der Hund', 'Der Hund ist klein.', 'Viele Tiere mit männlicher Form nehmen der. Wichtig: der Hund.'),
  ('44959747-7f8f-53e5-81ac-08233e8edd21', 'en', 'the dog', 'Der Hund ist klein.', 'Many animals with a male form use der. Key pair: der Hund.'),
  ('4d4314ab-a6cd-5c29-98e4-e04dcdca581b', 'de', 'der Zug', 'Der Zug kommt.', 'Zug hat keine sichere Endung. Für A1 fest merken: der Zug.'),
  ('4d4314ab-a6cd-5c29-98e4-e04dcdca581b', 'en', 'the train', 'Der Zug kommt.', 'Zug has no safe ending rule. For A1, memorize the pair: der Zug.'),
  ('5827d207-9510-572e-b5b4-4830933a3915', 'de', 'die Uhr', 'Die Uhr ist rund.', 'Uhr ist eine wichtige Ausnahme ohne -e. Kurz merken: die Uhr.'),
  ('5827d207-9510-572e-b5b4-4830933a3915', 'en', 'the clock', 'Die Uhr ist rund.', 'Uhr is an important exception without -e. Just remember: die Uhr.'),
  ('5afd94e7-811e-51fb-ba1d-88af604ec625', 'de', 'die Flasche', 'Die Flasche ist leer.', 'Flasche endet auf -e. Merke die -e-Hilfe: die Flasche.'),
  ('5afd94e7-811e-51fb-ba1d-88af604ec625', 'en', 'the bottle', 'Die Flasche ist leer.', 'Flasche ends in -e. Use the -e hint: die Flasche.'),
  ('5f84a843-af5c-532e-9f88-e0a8b9377abd', 'de', 'die Schule', 'Die Schule ist groß.', 'Schule endet auf -e. Sehr oft hilft das: die Schule.'),
  ('5f84a843-af5c-532e-9f88-e0a8b9377abd', 'en', 'the school', 'Die Schule ist groß.', 'Schule ends in -e. That is a strong hint for die: die Schule.'),
  ('6ff7dbc0-1567-5a19-92c6-e5c72579b200', 'de', 'das Kind', 'Das Kind spielt.', 'Junge Menschen können grammatisch das sein. Merke: das Kind.'),
  ('6ff7dbc0-1567-5a19-92c6-e5c72579b200', 'en', 'the child', 'Das Kind spielt.', 'Young people can be grammatically das. Remember: das Kind.'),
  ('75b43e71-af8d-59d8-9089-8ba153bb25fd', 'de', 'das Fahrrad', 'Das Fahrrad ist schnell.', 'Zusammengesetzte Wörter nehmen den Artikel vom letzten Teil. Rad ist das: das Fahrrad.'),
  ('75b43e71-af8d-59d8-9089-8ba153bb25fd', 'en', 'the bicycle', 'Das Fahrrad ist schnell.', 'Compound nouns take the article of the last part. Rad is das: das Fahrrad.'),
  ('798e0fbd-06b5-54f4-b94f-30cc141df22c', 'de', 'der Stuhl', 'Der Stuhl ist frei.', 'Stuhl ist ein Alltagswort ohne Regel. Als festes Paar lernen: der Stuhl.'),
  ('798e0fbd-06b5-54f4-b94f-30cc141df22c', 'en', 'the chair', 'Der Stuhl ist frei.', 'Stuhl has no safe ending rule. Learn it as a fixed pair: der Stuhl.'),
  ('7cd5b995-52f5-51dc-81a6-0d25e6ac2711', 'de', 'der Schlüssel', 'Der Schlüssel ist hier.', 'Wörter auf -el sind sehr oft der: der Schlüssel.'),
  ('7cd5b995-52f5-51dc-81a6-0d25e6ac2711', 'en', 'the key', 'Der Schlüssel ist hier.', 'Words ending in -el are very often der: der Schlüssel.'),
  ('8b2880f6-4285-5d67-8897-3cae2204f117', 'de', 'der Ball', 'Der Ball ist rund.', 'Viele kurze Gegenstände sind nicht automatisch der, aber Ball ist es: der Ball.'),
  ('8b2880f6-4285-5d67-8897-3cae2204f117', 'en', 'the ball', 'Der Ball ist rund.', 'Short object words are not always der, but Ball is: der Ball.'),
  ('8c2650cc-2539-510a-9370-b7b93223368c', 'de', 'der Park', 'Der Park ist grün.', 'Viele Orte mit kurzer, harter Form sind der. Für A1: der Park.'),
  ('8c2650cc-2539-510a-9370-b7b93223368c', 'en', 'the park', 'Der Park ist grün.', 'Many short place words use der. For A1, remember: der Park.'),
  ('90ab9861-eb6a-5b29-a229-441c9e6baa3c', 'de', 'das Auto', 'Das Auto ist neu.', 'Internationale Sachwörter sind oft das. Das hilft hier: das Auto.'),
  ('90ab9861-eb6a-5b29-a229-441c9e6baa3c', 'en', 'the car', 'Das Auto ist neu.', 'International object words are often das. This helps here: das Auto.'),
  ('aad5bc84-9185-5f65-abd6-b9cc1e514058', 'de', 'das Buch', 'Das Buch ist gut.', 'Buch hat keine sichere Endung. Lerne es als festes Paar: das Buch.'),
  ('aad5bc84-9185-5f65-abd6-b9cc1e514058', 'en', 'the book', 'Das Buch ist gut.', 'Buch has no safe ending rule. Learn it as a fixed pair: das Buch.'),
  ('abbfaf86-3156-5a5e-9cf6-bc8e079d18cf', 'de', 'die Küche', 'Die Küche ist sauber.', 'Küche endet auf -e. Das passt oft zu die: die Küche.'),
  ('abbfaf86-3156-5a5e-9cf6-bc8e079d18cf', 'en', 'the kitchen', 'Die Küche ist sauber.', 'Küche ends in -e. That often fits die: die Küche.'),
  ('b6383b12-e5ef-5660-a988-129804655ca0', 'de', 'der Löffel', 'Der Löffel ist klein.', 'Auch -el: der Löffel. Schlüssel und Löffel teilen der.'),
  ('b6383b12-e5ef-5660-a988-129804655ca0', 'en', 'the spoon', 'Der Löffel ist klein.', 'Another -el word: der Löffel. Schlüssel and Löffel both use der.'),
  ('c191b9a4-14ba-56cf-827f-a88f6687e7cf', 'de', 'die Tür', 'Die Tür ist offen.', 'Tür und Uhr sind kurze Ausnahmen. Beide sind die: die Tür, die Uhr.'),
  ('c191b9a4-14ba-56cf-827f-a88f6687e7cf', 'en', 'the door', 'Die Tür ist offen.', 'Tür and Uhr are short exceptions. Both use die: die Tür, die Uhr.'),
  ('cc615836-927f-5f62-9baa-6d22a8ee2261', 'de', 'der Computer', 'Der Computer ist an.', 'Viele Wörter auf -er sind der: der Computer.'),
  ('cc615836-927f-5f62-9baa-6d22a8ee2261', 'en', 'the computer', 'Der Computer ist an.', 'Many words ending in -er use der: der Computer.'),
  ('d2c45318-a638-5421-acd2-5f2299a2f151', 'de', 'die Blume', 'Die Blume ist schön.', 'Blume endet auf -e. Ein typisches die-Wort: die Blume.'),
  ('d2c45318-a638-5421-acd2-5f2299a2f151', 'en', 'the flower', 'Die Blume ist schön.', 'Blume ends in -e. A typical die word: die Blume.'),
  ('d655fd9c-ecf7-528b-a7e6-76991cffd6a2', 'de', 'der Schuh', 'Der Schuh ist schwarz.', 'Kleidung hat keinen sicheren Artikel. Merke als Paar: der Schuh.'),
  ('d655fd9c-ecf7-528b-a7e6-76991cffd6a2', 'en', 'the shoe', 'Der Schuh ist schwarz.', 'Clothing has no safe article rule. Learn the pair: der Schuh.'),
  ('d789e544-60b2-5d1d-9506-d03d6e3d652a', 'de', 'der Tisch', 'Der Tisch ist groß.', 'Tisch hat keine sichere Endung. Lerne es als festes Paar: der Tisch.'),
  ('d789e544-60b2-5d1d-9506-d03d6e3d652a', 'en', 'the table', 'Der Tisch ist groß.', 'Tisch has no safe ending rule. Learn it as a fixed pair: der Tisch.'),
  ('f15db869-d4a4-5ed3-a533-58678224e82b', 'de', 'das Haus', 'Das Haus ist alt.', 'Viele kurze Sachwörter musst du fest mit Artikel lernen. Für Haus gilt: das Haus.'),
  ('f15db869-d4a4-5ed3-a533-58678224e82b', 'en', 'the house', 'Das Haus ist alt.', 'Many short object words must be learned with the article. For Haus: das Haus.')
